{"name": "create_new_file", "arguments": {"filepath": "src/views/progreso.php", "contents": "\n<?php\n// progreso.php\n\nuse App\Models\\Progreso;\nuse App\Models\\Categorias;\n\n$progresos = Progreso::join('categorias', 'progreso.id_categoria', '=', 'categorias.id')->get();\n\n$title = \"Avance del Niño\";\ninclude_once '../partials/header.php';\n?>\n<div class=\"container mx-auto mt-10\">\n    <h1 class=\"text-2xl font-bold mb-4\">{$title}</h1>\n    <table class=\"w-full bg-white shadow-md rounded-lg overflow-hidden\">\n        <thead>\n            <tr class=\"bg-gray-800 text-white text-left py-3 px-4 \">\n                <th class=\"px-6 py-4\">Nombre</th>\n                <th class=\"px-6 py-4\">Categoría</th>\n                <th class=\"px-6 py-4\">Puntos</th>\n                <th class=\"px-6 py-4\">Estrellas</th>\n            </tr>\n        </thead>\n        <tbody>\n            <?php foreach ($progresos as $progress): \?>\n            <tr class=\"bg-gray-200 text-left hover:bg-gray-100 transition duration-300\">\n                <td class=\"px-6 py-4\">{$progress->nombre}</td>\n                <td class=\"px-6 py-4\">{$progress->categoria}</td>\n                <td class=\"px-6 py-4\">{$progress->puntos}</td>\n                <td class=\"px-6 py-4\">\n                    <?php $stars = floor($progress->puntos / 100); \?>\n                    <?php for ($i = 0; $i < $stars; $i++): \?>\n                        <span class=\"text-yellow-500\"><svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"currentColor\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"#FFB900\" class=\"w-6 h-6\">\n                            <path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M11.64 9l-.83 7a2 2 0 01-.98 2h5.28a2 2 0 01.98-2L15.36 9a2 2 0 01-.75-1.48 2 2 0 01-1.24-1.52H6.91A2 2 0 016.08 9h5.15l-.9-7a2 2 0 010-3.6zm7.6 0a2 2 0 110 4 2 2 0 010-4z\"></path>\n                        </svg></span>\n                    <?php endfor; \?>\n                </td>\n            </tr>\n            <?php endforeach; \?>\n        </tbody>\n    </table>\n</div>\n\n<div class=\"mt-6\">\n    <a href=\"../menu.php\" class=\"bg-gray-800 text-white py-2 px-4 rounded-lg hover:bg-gray-700\">Volver al Menú</a>\n</div>\n<?php include_once '../partials/footer.php'; \?>\n\n<style>\n    .container {\n        max-width: 800px;\n    }\n    table {\n        width: 100%;\n        border-collapse: collapse;\n    }\n    th, td {\n        border-bottom: 1px solid #ddd;\n        padding: 8px;\n    }\n    th {\n        background-color: #f2f2f2;\n    }\n</style>"}}}